// Parse le RSS Légifrance et filtre les items liés à la paie/RH
const xmlText = $input.first().json.data || $input.first().json.body || '';

// Si le RSS a échoué, retourner un tableau vide
if (!xmlText || typeof xmlText !== 'string' || xmlText.length < 100) {
  return [{ json: { questions: [], source: 'Légifrance RSS', note: 'RSS indisponible ou vide' } }];
}

// Extraction simple des titres depuis le XML
const titleRegex = /<title><!\[CDATA\[(.*?)\]\]><\/title>|<title>(.*?)<\/title>/g;
const titles = [];
let match;
while ((match = titleRegex.exec(xmlText)) !== null) {
  const title = (match[1] || match[2] || '').trim();
  if (title) titles.push(title);
}

// Mots-clés pour filtrer les items pertinents paie/RH
const keywords = [
  'paie', 'salaire', 'rémunération', 'cotisation', 'smic',
  'congé', 'travail', 'emploi', 'sécurité sociale', 'urssaf',
  'retraite', 'mutuelle', 'prévoyance', 'embauche', 'licenciement',
  'convention collective', 'code du travail', 'droit social',
  'bulletin', 'indemnité', 'prime', 'titre-restaurant',
  'télétravail', 'heures supplémentaires', 'dsn'
];

const relevant = titles.filter(t => {
  const lower = t.toLowerCase();
  return keywords.some(kw => lower.includes(kw));
});

// Transformer les titres en questions exploitables
const questions = relevant.slice(0, 10).map(t => ({
  question: `${t} : quelles conséquences pour la paie des TPE/PME en 2026 ?`,
  source: 'Légifrance - Journal Officiel',
  raw_title: t
}));

return [{ json: { questions, count: questions.length } }];

