// Parse la réponse OpenAI et extrait les questions
const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '[]';

let questions;
try {
  // Nettoyer le markdown potentiel
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  questions = JSON.parse(cleaned);
} catch (e) {
  console.log('Parse error, attempting recovery...');
  // Tenter de trouver le JSON dans le texte
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    questions = JSON.parse(jsonMatch[0]);
  } else {
    questions = [];
  }
}

return [{ json: { questions, count: questions.length, source: 'OpenAI PAA Generation' } }];

// Combiner les questions des deux sources (PAA + Légifrance)
const items = $input.all();

let allQuestions = [];

for (const item of items) {
  const questions = item.json.questions || [];
  for (const q of questions) {
    allQuestions.push({
      question: q.question,
      source: q.source || 'Unknown',
      signal: q.signal || q.raw_title || '',
      icp_target: q.icp_target || 'ICP 1+2',
      suggested_format: q.suggested_format || 'Article + FAQ'
    });
  }
}

// Déduplication basique (par question similaire)
const seen = new Set();
const unique = allQuestions.filter(q => {
  const key = q.question.toLowerCase().substring(0, 50);
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Retourner chaque question comme un item séparé pour le traitement en batch
return unique.map(q => ({ json: q }));

