// Combiner les données de la question avec son score
const batchItem = $('Traiter un par un').first().json;
const scoreResponse = $input.first().json;

const content = scoreResponse.choices?.[0]?.message?.content || '{}';
const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let scores;
try {
  scores = JSON.parse(cleaned);
} catch {
  scores = { score_novelty: 3, score_payfit_relevance: 3, score_volume: 3 };
}

const score_total = (
  (scores.score_novelty || 3) +
  (scores.score_payfit_relevance || 3) +
  (scores.score_volume || 3)
) / 3;

return [{
  json: {
    type: 'trend',
    data: {
      question: batchItem.question,
      source: batchItem.source,
      signal: batchItem.signal,
      score_novelty: scores.score_novelty || 3,
      score_payfit_relevance: scores.score_payfit_relevance || 3,
      score_volume: scores.score_volume || 3,
      score_total: Math.round(score_total * 100) / 100,
      icp_target: batchItem.icp_target || 'ICP 1+2',
      suggested_format: batchItem.suggested_format || 'Article + FAQ',
      status: 'new'
    }
  }
}];
